// Check environment variables and enable logging if possible.
func initLoggingFromEnv(db adbc.DatabaseLogging) {
	logLevel := slog.LevelError
	switch strings.ToLower(os.Getenv(logLevelEnvVar)) {
	case "debug":
		logLevel = slog.LevelDebug
	case "info":
		logLevel = slog.LevelInfo
	case "warn":
	case "warning":
		logLevel = slog.LevelWarn
	case "error":
		logLevel = slog.LevelError
	case "":
		return
	default:
		fmt.Fprintf(os.Stderr, "mariadb: to enable logging, set %s to 'debug', 'info', 'warn', or 'error'", logLevelEnvVar)
		return
	}

	var sink io.Writer
	sink = os.Stderr
	switch strings.ToLower(os.Getenv(logSinkEnvVar)) {
	case "stderr":
		// do nothing
	case "tempfile":
		// stopgap for debugging; eventually we should support things like
		// logging to ~/.local/share/adbc (or something) and rotation
		f, err := os.CreateTemp("", "adbc-mariadb.*.log")
		if err == nil {
			sink = f
		} else {
			fmt.Fprintf(os.Stderr, "[mariadb] could not open temporary log file: %v", err)
		}
	}

	h := slog.NewJSONHandler(sink, &slog.HandlerOptions{
		AddSource: false,
		Level:     logLevel,
	})
	logger := slog.New(h)
	db.SetLogger(logger)
}

