//export releasePartitions
func releasePartitions(partitions *C.struct_AdbcPartitions) {
	if partitions.private_data == nil {
		return
	}

	C.free(unsafe.Pointer(partitions.partitions))
	C.free(unsafe.Pointer(partitions.partition_lengths))
	C.free(partitions.private_data)
	partitions.partitions = nil
	partitions.partition_lengths = nil
	partitions.private_data = nil
}

//export MariaDBStatementExecutePartitions
func MariaDBStatementExecutePartitions(stmt *C.struct_AdbcStatement, schema *C.struct_ArrowSchema, partitions *C.struct_AdbcPartitions, affected *C.int64_t, err *C.struct_AdbcError) (code C.AdbcStatusCode) {
	defer func() {
		if e := recover(); e != nil {
			code = poison(err, "AdbcStatementExecutePartitions", e)
		}
	}()
	st := checkStmtInit(stmt, err, "AdbcStatementExecutePartitions")
	if st == nil {
		return C.ADBC_STATUS_INVALID_STATE
	}

	sc, part, n, e := st.stmt.ExecutePartitions(st.newContext())
	if e != nil {
		return C.AdbcStatusCode(errToAdbcErr(err, e))
	}

	if partitions == nil {
		setErr(err, "AdbcStatementExecutePartitions: partitions output struct is null")
		return C.ADBC_STATUS_INVALID_ARGUMENT
	}

	if affected != nil {
		*affected = C.int64_t(n)
	}

	if sc != nil && schema != nil {
		cdata.ExportArrowSchema(sc, toCdataSchema(schema))
	}

	partitions.num_partitions = C.size_t(part.NumPartitions)
	partitions.partitions = (**C.cuint8_t)(C.malloc(C.size_t(unsafe.Sizeof((*C.uint8_t)(nil)) * uintptr(part.NumPartitions))))
	partitions.partition_lengths = (*C.size_t)(C.malloc(C.size_t(unsafe.Sizeof(C.size_t(0)) * uintptr(part.NumPartitions))))

	// Copy into C-allocated memory to avoid violating CGO rules
	totalLen := 0
	for _, p := range part.PartitionIDs {
		totalLen += len(p)
	}
	partitions.private_data = C.calloc(C.size_t(totalLen), C.size_t(1))
	dst := fromCArr[byte]((*byte)(partitions.private_data), totalLen)

	partIDs := fromCArr[*C.cuint8_t](partitions.partitions, int(partitions.num_partitions))
	partLens := fromCArr[C.size_t](partitions.partition_lengths, int(partitions.num_partitions))
	for i, p := range part.PartitionIDs {
		partIDs[i] = (*C.cuint8_t)(&dst[0])
		copy(dst, p)
		dst = dst[len(p):]
		partLens[i] = C.size_t(len(p))
	}

	partitions.release = (*[0]byte)(C.releasePartitions)
	return C.ADBC_STATUS_OK
}

//export AdbcDriverMariaDBInit
func AdbcDriverMariaDBInit(version C.int, rawDriver *C.void, err *C.struct_AdbcError) C.AdbcStatusCode {
	driver := (*C.struct_AdbcDriver)(unsafe.Pointer(rawDriver))

	switch version {
	case C.ADBC_VERSION_1_0_0:
		sink := fromCArr[byte]((*byte)(unsafe.Pointer(driver)), C.ADBC_DRIVER_1_0_0_SIZE)
		memory.Set(sink, 0)
	case C.ADBC_VERSION_1_1_0:
		sink := fromCArr[byte]((*byte)(unsafe.Pointer(driver)), C.ADBC_DRIVER_1_1_0_SIZE)
		memory.Set(sink, 0)
	default:
		setErr(err, "Only version 1.0.0/1.1.0 supported, got %d", int(version))
		return C.ADBC_STATUS_NOT_IMPLEMENTED
	}

	driver.DatabaseInit = (*[0]byte)(C.MariaDBDatabaseInit)
	driver.DatabaseNew = (*[0]byte)(C.MariaDBDatabaseNew)
	driver.DatabaseRelease = (*[0]byte)(C.MariaDBDatabaseRelease)
	driver.DatabaseSetOption = (*[0]byte)(C.MariaDBDatabaseSetOption)

	driver.ConnectionNew = (*[0]byte)(C.MariaDBConnectionNew)
	driver.ConnectionInit = (*[0]byte)(C.MariaDBConnectionInit)
	driver.ConnectionRelease = (*[0]byte)(C.MariaDBConnectionRelease)
	driver.ConnectionSetOption = (*[0]byte)(C.MariaDBConnectionSetOption)
	driver.ConnectionGetInfo = (*[0]byte)(C.MariaDBConnectionGetInfo)
	driver.ConnectionGetObjects = (*[0]byte)(C.MariaDBConnectionGetObjects)
	driver.ConnectionGetTableSchema = (*[0]byte)(C.MariaDBConnectionGetTableSchema)
	driver.ConnectionGetTableTypes = (*[0]byte)(C.MariaDBConnectionGetTableTypes)
	driver.ConnectionReadPartition = (*[0]byte)(C.MariaDBConnectionReadPartition)
	driver.ConnectionCommit = (*[0]byte)(C.MariaDBConnectionCommit)
	driver.ConnectionRollback = (*[0]byte)(C.MariaDBConnectionRollback)

	driver.StatementNew = (*[0]byte)(C.MariaDBStatementNew)
	driver.StatementRelease = (*[0]byte)(C.MariaDBStatementRelease)
	driver.StatementSetOption = (*[0]byte)(C.MariaDBStatementSetOption)
	driver.StatementSetSqlQuery = (*[0]byte)(C.MariaDBStatementSetSqlQuery)
	driver.StatementSetSubstraitPlan = (*[0]byte)(C.MariaDBStatementSetSubstraitPlan)
	driver.StatementBind = (*[0]byte)(C.MariaDBStatementBind)
	driver.StatementBindStream = (*[0]byte)(C.MariaDBStatementBindStream)
	driver.StatementExecuteQuery = (*[0]byte)(C.MariaDBStatementExecuteQuery)
	driver.StatementExecutePartitions = (*[0]byte)(C.MariaDBStatementExecutePartitions)
	driver.StatementGetParameterSchema = (*[0]byte)(C.MariaDBStatementGetParameterSchema)
	driver.StatementPrepare = (*[0]byte)(C.MariaDBStatementPrepare)

	if version == C.ADBC_VERSION_1_1_0 {
		driver.ErrorGetDetailCount = (*[0]byte)(C.MariaDBErrorGetDetailCount)
		driver.ErrorGetDetail = (*[0]byte)(C.MariaDBErrorGetDetail)
		driver.ErrorFromArrayStream = (*[0]byte)(C.MariaDBErrorFromArrayStream)

		driver.DatabaseGetOption = (*[0]byte)(C.MariaDBDatabaseGetOption)
		driver.DatabaseGetOptionBytes = (*[0]byte)(C.MariaDBDatabaseGetOptionBytes)
		driver.DatabaseGetOptionDouble = (*[0]byte)(C.MariaDBDatabaseGetOptionDouble)
		driver.DatabaseGetOptionInt = (*[0]byte)(C.MariaDBDatabaseGetOptionInt)
		driver.DatabaseSetOptionBytes = (*[0]byte)(C.MariaDBDatabaseSetOptionBytes)
		driver.DatabaseSetOptionDouble = (*[0]byte)(C.MariaDBDatabaseSetOptionDouble)
		driver.DatabaseSetOptionInt = (*[0]byte)(C.MariaDBDatabaseSetOptionInt)

		driver.ConnectionCancel = (*[0]byte)(C.MariaDBConnectionCancel)
		driver.ConnectionGetOption = (*[0]byte)(C.MariaDBConnectionGetOption)
		driver.ConnectionGetOptionBytes = (*[0]byte)(C.MariaDBConnectionGetOptionBytes)
		driver.ConnectionGetOptionDouble = (*[0]byte)(C.MariaDBConnectionGetOptionDouble)
		driver.ConnectionGetOptionInt = (*[0]byte)(C.MariaDBConnectionGetOptionInt)
		driver.ConnectionGetStatistics = (*[0]byte)(C.MariaDBConnectionGetStatistics)
		driver.ConnectionGetStatisticNames = (*[0]byte)(C.MariaDBConnectionGetStatisticNames)
		driver.ConnectionSetOptionBytes = (*[0]byte)(C.MariaDBConnectionSetOptionBytes)
		driver.ConnectionSetOptionDouble = (*[0]byte)(C.MariaDBConnectionSetOptionDouble)
		driver.ConnectionSetOptionInt = (*[0]byte)(C.MariaDBConnectionSetOptionInt)

		driver.StatementCancel = (*[0]byte)(C.MariaDBStatementCancel)
		driver.StatementExecuteSchema = (*[0]byte)(C.MariaDBStatementExecuteSchema)
		driver.StatementGetOption = (*[0]byte)(C.MariaDBStatementGetOption)
		driver.StatementGetOptionBytes = (*[0]byte)(C.MariaDBStatementGetOptionBytes)
		driver.StatementGetOptionDouble = (*[0]byte)(C.MariaDBStatementGetOptionDouble)
		driver.StatementGetOptionInt = (*[0]byte)(C.MariaDBStatementGetOptionInt)
		driver.StatementSetOptionBytes = (*[0]byte)(C.MariaDBStatementSetOptionBytes)
		driver.StatementSetOptionDouble = (*[0]byte)(C.MariaDBStatementSetOptionDouble)
		driver.StatementSetOptionInt = (*[0]byte)(C.MariaDBStatementSetOptionInt)
	}

	return C.ADBC_STATUS_OK
}

